var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"모리 칼리오페는 그녀의 시청자, 데드 비츠를 위해 직접 쓴 편지를 낭독하기로 했다.","JPN":"森カリオペは彼女のリスナー、Dead Beatsのために自筆の手紙を朗読すると決めた。","ENG":"Mori Calliope decided to read a special letter that she has written for her loyal viewers, Dead Beats.","TWN":"Mori Calliope decided to read a special letter that she has written for her loyal viewers, Dead Beats."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"곧, 그녀가 무대 뒤에 도착했다는 무전이 들려왔다.","JPN":"先ほど、彼女がバックステージに着いたとの連絡があった。","ENG":"Soon, a radio call arrived saying that she has arrived backstage.","TWN":"Soon, a radio call arrived saying that she has arrived backstage."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"HOLY_KNIGHT_CLB_003","text":{"KOREA":"음…. 크흠. 이거 꼭 내가 읽어야 돼? 좀 간질간질 한데…….","JPN":"はぁ、ふむ。これ私が読まないといけないのか？　ちょっと恥ずかしすぎてハラハラするんだけど……","ENG":"Ummm…. Do I really have to read this? It’s too cringe, man…….","TWN":"Ummm…. Do I really have to read this? It’s too cringe, man……."},"stage":{"bg":"CLB_003","bgm":"COLLABO_2022_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_CLB_003","face":"UNIT_SURPRISE"},"R":null}},"voice":"clb003_lifetime_voice_101"},{"id":"L9_1","type":"dialog","speaker":"HOLY_KNIGHT_CLB_003","text":{"KOREA":"직접 쓴 걸로는 부족하다는 얘기지?","JPN":"自筆の手紙だけじゃ満足しないってことだな？","ENG":"You’re saying that just writing alone isn’t enough, right?","TWN":"You’re saying that just writing alone isn’t enough, right?"},"stage":{"bg":"CLB_003","bgm":"COLLABO_2022_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_CLB_003","face":"UNIT_IDLE"},"R":null}},"voice":"clb003_lifetime_voice_102"},{"id":"L10_1","type":"dialog","speaker":"HOLY_KNIGHT_CLB_003","text":{"KOREA":"알았어, 읽으면 되잖아. 읽으면….","JPN":"わかったよ。読めばいいんだろう、読めば。","ENG":"Alright, alright I will read it. Man….","TWN":"Alright, alright I will read it. Man…."},"stage":{"bg":"CLB_003","bgm":"COLLABO_2022_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_CLB_003","face":"UNIT_DESPAIR"},"R":null}},"voice":"clb003_lifetime_voice_103"},{"id":"L11_1","type":"dialog","speaker":"HOLY_KNIGHT_CLB_003","text":{"KOREA":"흠흠. 그러니까…… 데드 비츠에게.","JPN":"えへん……えっと、親愛なるDead Beats達へ。","ENG":"Ahem! Ehhh…… Dear Dead Beats.","TWN":"Ahem! Ehhh…… Dear Dead Beats."},"stage":{"bg":"CLB_003","bgm":"COLLABO_2022_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_CLB_003","face":"UNIT_IDLE"},"R":null}},"voice":"clb003_lifetime_voice_104"},{"id":"L12_1","type":"dialog","speaker":"HOLY_KNIGHT_CLB_003","text":{"KOREA":"알아, 오글거리는 거. 조금만 버텨 봐.","JPN":"そうだよ。ハラハラするよ。ちょっと我慢しな。","ENG":"Yes, I know, it’s cringy, but just hang in there a moment.","TWN":"Yes, I know, it’s cringy, but just hang in there a moment."},"stage":{"bg":"CLB_003","bgm":"COLLABO_2022_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_CLB_003","face":"UNIT_LAUGH"},"R":null}},"voice":"clb003_lifetime_voice_105"},{"id":"L13_1","type":"dialog","speaker":"HOLY_KNIGHT_CLB_003","text":{"KOREA":"저승에서 올라와서 적응하기 힘들었을 때 방송이라는 걸 생애 처음으로 접해 봤어.","JPN":"地上に上がってなれない日々に初めて配信というものに触れることができた。","ENG":"I was a reaper who had difficulties adjusting to the surface world and live streaming for the first time.","TWN":"I was a reaper who had difficulties adjusting to the surface world and live streaming for the first time."},"stage":{"bg":"CLB_003","bgm":"COLLABO_2022_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_CLB_003","face":"UNIT_IDLE"},"R":null}},"voice":"clb003_lifetime_voice_106"},{"id":"L14_1","type":"dialog","speaker":"HOLY_KNIGHT_CLB_003","text":{"KOREA":"네가 응원과 사랑으로 날 지지해 주지 않았다면, 지금 네가 알고 있는 칼리오페 모리는 이 자리에 없었을 거야.","JPN":"お前が愛と応援で俺を支えてくれなかったら、お前が知る森カリオペはこの場にいなかったと思う。","ENG":"And if it wasn’t for you guys and all the love and support you’ve given me, I don’t think the Calliope Mori you know would even be here today.","TWN":"And if it wasn’t for you guys and all the love and support you’ve given me, I don’t think the Calliope Mori you know would even be here today."},"stage":{"bg":"CLB_003","bgm":"COLLABO_2022_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_CLB_003","face":"UNIT_IDLE"},"R":null}},"voice":"clb003_lifetime_voice_107"},{"id":"L15_1","type":"dialog","speaker":"HOLY_KNIGHT_CLB_003","text":{"KOREA":"아마, 영혼을 수확하겠다고 길거리 떠돌면서 닌자들이랑 싸우고 있거나… 뭔가를 하고 있었겠지.","JPN":"多分魂を刈り取るために街を徘徊しながら忍者と戦ったり……なんか別のものをやってたはずだ。","ENG":"Perhaps I might be wandering around the streets trying to collect souls and fighting ninjas, or… something.","TWN":"Perhaps I might be wandering around the streets trying to collect souls and fighting ninjas, or… something."},"stage":{"bg":"CLB_003","bgm":"COLLABO_2022_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_CLB_003","face":"UNIT_LAUGH"},"R":null}},"voice":"clb003_lifetime_voice_108"},{"id":"L16_1","type":"dialog","speaker":"HOLY_KNIGHT_CLB_003","text":{"KOREA":"차갑게 식은 피를 보는 대신 근사한 데드 비츠랑 시간을 보내는 걸 내가 얼마나 좋아하는지 넌 절대 모를걸?","JPN":"冷めた血を眺めるより、Dead Beatsと時間を過ごすことを俺がどれだけ大事にしているかきっとお前はわからないよな？","ENG":"You guys have no idea how much I love being with the rad Dead Beats than seeing cold red blood.","TWN":"You guys have no idea how much I love being with the rad Dead Beats than seeing cold red blood."},"stage":{"bg":"CLB_003","bgm":"COLLABO_2022_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_CLB_003","face":"UNIT_PRIDE"},"R":null}},"voice":"clb003_lifetime_voice_109"},{"id":"L17_1","type":"dialog","speaker":"HOLY_KNIGHT_CLB_003","text":{"KOREA":"그래서 내가 하고 싶은 말은…… 그러니까…… 모든 게 고맙다고.","JPN":"まぁ、あれだ。俺が言いたいのは……だから……いつもありがとうと言いたいんだ。","ENG":"The point I am trying to make here is that…… uh…… thank you for everything.","TWN":"The point I am trying to make here is that…… uh…… thank you for everything."},"stage":{"bg":"CLB_003","bgm":"COLLABO_2022_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_CLB_003","face":"UNIT_SERIOUS"},"R":null}},"voice":"clb003_lifetime_voice_110"},{"id":"L18_1","type":"dialog","speaker":"HOLY_KNIGHT_CLB_003","text":{"KOREA":"지… 진짜야!","JPN":"う、嘘じゃないからな！","ENG":"I… I mean it!","TWN":"I… I mean it!"},"stage":{"bg":"CLB_003","bgm":"COLLABO_2022_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_CLB_003","face":"UNIT_SURPRISE"},"R":null}},"voice":"clb003_lifetime_voice_111"}]`);export{e as default};